form:Form.form:Scripts:
		function RefreshButtons()
{
	switch(Ctrl("main").GetMode())
	{
		case "PASO2":
			CtrlEnabled("ACCEPT", Ctrl("ImportLIST").GetXValue().split(":")[0]=="INT");
			CtrlEnabled("NEXT"  , Ctrl("ImportLIST").GetXValue().split(":")[0]!="INT");
			break;

		case "PASO3W":               
			CtrlEnabled("oi_organigrama", Ctrl("chkOVERWRITE").GetXValue()=="1" || Ctrl("main").GetMode()=="PASO3W");
			CtrlEnabled("oi_wf"         , Ctrl("chkOVERWRITE").GetXValue()=="1");

			CtrlEnabled("txtCODE", Ctrl("chkNEW").GetXValue()=="1");
			CtrlEnabled("txtDESC", Ctrl("chkNEW").GetXValue()=="1");

			CtrlEnabled("ACCEPT" , Ctrl("chkNEW").GetXValue()=="1" || Ctrl("chkOVERWRITE").GetXValue()=="1");
			break;

		case "PASO3WA":               
			CtrlEnabled("chkAPPEND", false);
			break;

		case "PASO3O":  
			CtrlEnabled("oi_organigrama", Ctrl("chkOVERWRITE").GetXValue()=="1" || Ctrl("chkAPPEND").GetXValue()=="1");

			CtrlEnabled("txtCODE", Ctrl("chkNEW").GetXValue()=="1");
			CtrlEnabled("txtDESC", Ctrl("chkNEW").GetXValue()=="1");

			CtrlEnabled("ACCEPT" , Ctrl("chkNEW").GetXValue()=="1" || Ctrl("chkOVERWRITE").GetXValue()=="1" || Ctrl("chkAPPEND").GetXValue()=="1");
			CtrlEnabled("chkETTY", Ctrl("chkNEW").GetXValue()=="1" || Ctrl("chkOVERWRITE").GetXValue()=="1");
			break;
	}
}

function ClickList()
{                 
	Ctrl("hEleType"   ).SetXValue(Ctrl("ImportLIST").GetXValue().split(":")[0]);
	Ctrl("hEleVersion").SetXValue(Ctrl("ImportLIST").GetSelectAttrValue("version"));
	RefreshButtons();
}

function ChangeOVER()
{                 
	if (Ctrl("chkOVERWRITE").GetXValue()=="1") 
	{
		switch(Ctrl("main").GetMode())
		{
			case "PASO3W":               
				Ctrl("chkNEW").SetXValue("0");
			  Ctrl("hModType").SetXValue("O");
				break;

			case "PASO3O":  
				Ctrl("chkNEW").SetXValue("0");
				Ctrl("chkAPPEND").SetXValue("0");
			  Ctrl("hModType").SetXValue("O");
				break;
		}
	}
	RefreshButtons();
}

function ChangeNEW()
{                   
	if (Ctrl("chkNEW").GetXValue()=="1") 
	{
		switch(Ctrl("main").GetMode())
		{
			case "PASO3W":               
				Ctrl("chkOVERWRITE").SetXValue("0");
				Ctrl("hModType").SetXValue("N");
				break;

			case "PASO3O":  
				Ctrl("chkOVERWRITE").SetXValue("0");
				Ctrl("chkAPPEND").SetXValue("0");     
				Ctrl("hModType").SetXValue("N");
				break;
		}
	}
	RefreshButtons();
}

function ChangeAPPEND()
{                   
	if (Ctrl("chkAPPEND").GetXValue()=="1") 
	{
		Ctrl("chkNEW").SetXValue("0");
		Ctrl("chkOVERWRITE").SetXValue("0");
		Ctrl("chkETTY").SetXValue("1");

		Ctrl("hModType").SetXValue("A");
	}
	RefreshButtons();
}

function ReqO(pObj)
{                 
	if (Ctrl("chkOVERWRITE").GetXValue()!="1") return true;
	if (pObj.GetXValue()=="") 
	{
		pObj.SetError("El valor es requerido");
		return false;
	}
	return true;
}

function ReqN(pObj)
{                 
	if (Ctrl("chkNEW").GetXValue()!="1") return true;
	if (pObj.GetXValue()=="") 
	{
		pObj.SetError("El valor es requerido");
		return false;
	}
	return true;
}


function OnLoad()
{
	switch(Ctrl("main").GetMode())
	{
		case "PASO2":
			ClickList();
			break;      

		case "PASO3WA":
			Ctrl("chkAPPEND").SetXValue("1");
			Ctrl("hModType").SetXValue("A");
			RefreshButtons();
			break;

		default:
			RefreshButtons();
			break;
	}
}


function ACCEPT()
{
	if (Ctrl("ImportLIST"))
		if (Ctrl("ImportLIST").GetSelectAttrValue("exist")=="1")
			if (!confirm("La Interface de Integración ya existe\n¿Desea sobrescribirla?")) return false;

	return true;
}
